		transportTelemetry := &EvidenceAssemblyTelemetry{
			Sections:    built.Sections,
			InputBytes:  len(prompt),
			OutputBytes: 0,
			ElapsedMS:   durationMS,
			Harness:     reviewHarness,
			Model:       reviewRouteLabel,
		}
